mapper.select:
select id, source, frame, customer, time, number, total , actual , money , cost , account , people , logistics, file, data, more, examine, nucleus, cse, invoice, `check`, user
from sre

    left join
    (
        select pid from sre_info where goods like CONCAT('%', #{query.goods}, '%')
    ) as p
    on p.pid = sre.id



        and id = #{query.id}


        and customer = #{query.customer}


        and people = #{query.people}


        and time >= #{query.begin}


        and #{query.end} >= time


        and user = #{query.user}


        and examine = #{query.examine}


        and nucleus = #{query.nucleus}


        and cse = #{query.cse}


        and invoice = #{query.invoice}


        and `check` = #{query.check}


        and data = #{query.data}
